import os, re

# Walk through all .rs files in crates/ directory
tag_components = []
resource_unit_structs = []
non_component_unit_structs = []

# Regex for unit struct definition: optional pub, then struct Name;
unit_struct_re = re.compile(r'^\s*(pub\s+)?struct\s+(\w+);')
derive_re = re.compile(r'#\s*\[derive\s*\(([^)]*)\)\]')

for root, dirs, files in os.walk('crates'):
    for f in files:
        if not f.endswith('.rs'):
            continue
        path = os.path.join(root, f)
        with open(path, 'r', encoding='utf-8', errors='replace') as fp:
            try:
                lines = fp.readlines()
            except:
                continue

        i = 0
        while i < len(lines):
            line = lines[i]
            m = unit_struct_re.match(line)
            if m:
                struct_name = m.group(2)
                # Look backwards for derive attributes
                derives = set()
                j = i - 1
                while j >= 0:
                    dj = lines[j].strip()
                    dm = derive_re.match(dj)
                    if dm:
                        for attr in dm.group(1).split(','):
                            derives.add(attr.strip())
                        j -= 1
                    elif dj == '' or dj.startswith('///') or dj.startswith('//') or dj.startswith('#[') or dj.startswith('#!['):
                        j -= 1
                    else:
                        break

                rel_path = os.path.normpath(path)
                if 'Component' in derives:
                    if 'Resource' in derives:
                        resource_unit_structs.append((rel_path, i+1, struct_name, sorted(derives)))
                    else:
                        tag_components.append((rel_path, i+1, struct_name, sorted(derives)))
                else:
                    non_component_unit_structs.append((rel_path, i+1, struct_name, sorted(derives)))
            i += 1

print('=== TAG COMPONENTS (zero-field struct with derive(Component) and NOT derive(Resource)) ===')
for path, ln, name, derives in sorted(tag_components):
    print(f'{path}:{ln}  pub struct {name};  derives={derives}')

print()
print(f'Total Tag Components: {len(tag_components)}')

print()
print('=== RESOURCE unit structs (excluded - have Component+Resource derives) ===')
for path, ln, name, derives in resource_unit_structs:
    print(f'{path}:{ln}  pub struct {name};  derives={derives}')

print()
print('=== Non-Component unit structs (for reference) ===')
for path, ln, name, derives in non_component_unit_structs:
    print(f'{path}:{ln}  pub struct {name};  derives={derives}')
"

