import os, re

# Find Component unit structs that might have been missed (not starting with 'pub ')
derive_re = re.compile(r'#\s*\[derive\s*\(([^)]*)\)\]')
unit_struct_re = re.compile(r'^\s*(pub\s+)?(struct)\s+(\w+);')

tag_components = []
resource_excluded = []

for root, dirs, files in os.walk('.'):
    if '.git' in root or 'thirdparty' in root or 'target' in root:
        continue
    for f in files:
        if not f.endswith('.rs'):
            continue
        path = os.path.join(root, f)
        try:
            with open(path, 'r', encoding='utf-8', errors='replace') as fp:
                content = fp.read()
                lines = content.split('\n')
        except:
            continue

        i = 0
        while i < len(lines):
            line = lines[i]
            m = unit_struct_re.match(line)
            if m:
                struct_name = m.group(3)
                is_pub = m.group(1) is not None
                derives = set()
                j = i - 1
                while j >= 0:
                    dj = lines[j].strip()
                    dm = derive_re.match(dj)
                    if dm:
                        for attr in dm.group(1).split(','):
                            derives.add(attr.strip())
                        j -= 1
                    elif dj == '' or dj.startswith('///') or dj.startswith('//') or dj.startswith('#[') or dj.startswith('#!['):
                        j -= 1
                    else:
                        break
                if 'Component' in derives and 'Resource' not in derives:
                    rel_path = os.path.normpath(path)
                    tag_components.append((rel_path, i+1, struct_name, is_pub))
            i += 1

# Also check for impl Component for unit structs (without derive)
impl_re = re.compile(r'impl\s+Component\s+for\s+(\w+)')
for root, dirs, files in os.walk('.'):
    if '.git' in root or 'thirdparty' in root or 'target' in root:
        continue
    for f in files:
        if not f.endswith('.rs'):
            continue
        path = os.path.join(root, f)
        try:
            with open(path, 'r', encoding='utf-8', errors='replace') as fp:
                content = fp.read()
        except:
            continue
        for m in impl_re.finditer(content):
            name = m.group(1)
            rel_path = os.path.normpath(path)
            # Check line number
            lines = content.split('\n')
            for li, line in enumerate(lines):
                if f'impl Component for {name}' in line or f'impl Component for {name}' in line:
                    # Check if this is a unit struct
                    for uli in range(max(0, li-10), li):
                        um = unit_struct_re.match(lines[uli])
                        if um and um.group(3) == name:
                            tag_components.append((rel_path, uli+1, name, True))
                    break

# Deduplicate
seen = set()
unique = []
for item in tag_components:
    key = (item[0], item[1])
    if key not in seen:
        seen.add(key)
        unique.append(item)

print('=== ALL TAG COMPONENTS (zero-field structs with derive(Component) or impl Component for) ===')
for path, ln, name, is_pub in sorted(unique):
    pub_str = 'pub ' if is_pub else ''
    print(f'{path}:{ln}  {pub_str}struct {name};')

print(f'\nTotal: {len(unique)}')
"

