        try:
            with open(path, 'r', encoding='utf-8', errors='replace') as fp:
                content = fp.read()
                lines = content.split('\n')
        except:
            continue

        # Find all enums in this file
        enum_names = set()
        for line in lines:
            em = re.match(r'^\s*(pub\s+)?enum\s+(\w+)\s*\{', line)
            if em:
                enum_names.add(em.group(2))

        i = 0
        while i < len(lines):
            line = lines[i]
            m = struct_with_fields_re.match(line)
            if m:
                struct_name = m.group(2)
                derives = set()
                j = i - 1
                while j >= 0:
                    dj = lines[j].strip()
                    dm = derive_re.match(dj)
                    if dm:
                        for attr in dm.group(1).split(','):
                            derives.add(attr.strip())
                        j -= 1
                    elif dj == '' or dj.startswith('///') or dj.startswith('//') or dj.startswith('#[') or dj.startswith('#!['):
                        j -= 1
