                    field_types = set()
                    for ft in re.findall(r':\s*(\w+)\s*[,}]', body):
                        if ft in enum_names:
                            field_types.add(ft)
                    for ft in re.findall(r':\s*Option<(\w+)>', body):
                        if ft in enum_names:
                            field_types.add(f'Option<{ft}>')
                    for ft in re.findall(r':\s*Vec<(\w+)>', body):
                        if ft in enum_names:
                            field_types.add(f'Vec<{ft}>')

                    if field_types:
                        rel_path = os.path.normpath(path)
                        all_enum_components.append((rel_path, i+1, struct_name, sorted(field_types)))
            i += 1

print('=== Component structs with local enum fields ===')
for path, ln, name, types in sorted(all_enum_components):
    print(f'{path}:{ln}  pub struct {name}  fields: {types}')

print(f'\nTotal: {len(all_enum_components)}')
