import os, re

derive_re = re.compile(r'#\s*\[derive\s*\(([^)]*)\)\]')
struct_with_fields_re = re.compile(r'^\s*(pub\s+)?struct\s+(\w+)\s*\{')

enum_components = []

for root, dirs, files in os.walk('.'):
    if '.git' in root or 'thirdparty' in root or 'target' in root:
        continue
    for f in files:
        if not f.endswith('.rs'):
            continue
        path = os.path.join(root, f)
        try:
            with open(path, 'r', encoding='utf-8', errors='replace') as fp:
                content = fp.read()
                lines = content.split('\n')
        except:
            continue

        enum_names = set()
        for line in lines:
            em = re.match(r'^\s*(pub\s+)?enum\s+(\w+)\s*\{', line)
            if em:
                enum_names.add(em.group(2))

        i = 0
        while i < len(lines):
            line = lines[i]
            m = struct_with_fields_re.match(line)
            if m:
                struct_name = m.group(2)
                derives = set()
                j = i - 1
                while j >= 0:
                    dj = lines[j].strip()
                    dm = derive_re.match(dj)
                    if dm:
                        for attr in dm.group(1).split(','):
                            derives.add(attr.strip())
                        j -= 1
                    elif dj == '' or dj.startswith('///') or dj.startswith('//') or dj.startswith('#[') or dj.startswith('#!['):
                        j -= 1
                    else:
                        break

                if 'Component' in derives and 'Resource' not in derives:
                    body_start = i + 1
                    brace_depth = 1
                    body_lines = []
                    for k in range(body_start, len(lines)):
                        body_lines.append(lines[k])
                        brace_depth += lines[k].count('{') - lines[k].count('}')
                        if brace_depth <= 0:
                            break
                    body = '\n'.join(body_lines)

                    field_types = set()
                    for ft in re.findall(r':\s*(\w+)\s*[,}]', body):
                        if ft in enum_names:
                            field_types.add(ft)
                    for ft in re.findall(r':\s*Option<(\w+)>', body):
                        if ft in enum_names:
                            field_types.add(f'Option<{ft}>')
                    for ft in re.findall(r':\s*Vec<(\w+)>', body):
                        if ft in enum_names:
                            field_types.add(f'Vec<{ft}>')

                    if field_types:
                        rel_path = os.path.normpath(path)
                        enum_components.append((rel_path, i+1, struct_name, sorted(field_types)))
            i += 1

print('=== All Component structs with local enum fields ===')
for path, ln, name, types in sorted(enum_components):
    print(f'{path}:{ln}  pub struct {name}  enum fields: {types}')
print(f'\nTotal: {len(enum_components)}')
"
